      const fillMeta = {};
      Object.keys(u.fills).forEach((id) => { const f = u.fills[id]; fillMeta[id] = { kind: f.kind, name: f.name, dur: f.dur, remoteUrl: f.remoteUrl || null }; });   // remoteUrl: ☁ 클라우드 백업 — blob 없이도 새로고침 복원
