      if (s.isTitle) { try { const rb = await idbGet("sessTitleRef"); if (rb instanceof Blob) E.using._titleRefFile = rb; } catch (_) {} }   // 🎬 타이틀 참조사진 복원
      if (s.easyIdx != null) E.easyIdx = s.easyIdx;
