      slots: [{ id: uid(), dur: 3, label: "", auto: true, easyTrim: has("length") }],   // 영상넣기 = 자율컷(무제한). 컷길이 기능 있으면 길이조절 켬.
      texts: (has("caption") || has("setup")) ? [Object.assign({ id: uid(), text: "여기에 자막을 입력하세요" }, palCaptionTextProps(P.demo && P.demo.captionStyle))] : [],
