    if (!E._pubAdminTried) { E._pubAdminTried = true; if (!(E.published && E.published.length)) { try { loadPublished().then(() => { if (E.view === "admin") renderAdmin(); }); } catch (_) {} } }
    const liveIds = new Set((E.published || []).map((p) => p && p.id).filter(Boolean));
