  // 릴스화면(UI PNG) 오버레이
  async function loadReels() {
    try { const b = await idbGet("reelsOverlay"); if (b instanceof Blob) E.reelsUrl = URL.createObjectURL(b); } catch (_) {}
    try { E.reelsOn = !!(await idbGet("reelsOn")); } catch (_) {}
  }
  function updateReelsOverlay() {
    const img = $("#esReelsOverlay"); if (!img) return;
    if (E.reelsOn && E.reelsUrl) { if (img._url !== E.reelsUrl) { img.src = E.reelsUrl; img._url = E.reelsUrl; } img.style.display = "block"; }
    else img.style.display = "none";
    const cb = $("#esReels"); if (cb) cb.checked = E.reelsOn;
    const pick = $("#esReelsPick"); if (pick) pick.textContent = E.reelsUrl ? "UI 이미지 변경" : "UI 이미지";
  }
  // ── 로고 오버레이 (PNG) — 스테이지 위에 올리고 드래그·크기조절, 타임라인 로고 레인 ──
  const LOGO_BASE = 25;   // 기본 폭 = 화면의 25% (scale=1)
  const LOGO_FX = [
    { k: "none", label: "없음" },
    { k: "fade", label: "페이드 인·아웃" },
    { k: "fadein", label: "페이드 인" },
    { k: "fadeout", label: "페이드 아웃" },
    { k: "pop", label: "팝(통통)" },
    { k: "zoom", label: "줌 인" },
    { k: "blink", label: "깜빡임" },
  ];
  // tp = 로고 노출 구간 진행도(0..1). {opacity, scale}
  function logoFx(fx, tp) {
    tp = clamp(tp, 0, 1);
    const fin = clamp(tp / 0.15, 0, 1), fout = clamp((1 - tp) / 0.18, 0, 1);
    const ease = 1 - Math.pow(1 - fin, 3);
    const back = 1 + 2.70158 * Math.pow(fin - 1, 3) + 1.70158 * Math.pow(fin - 1, 2);
    switch (fx) {
      case "fade": return { opacity: Math.min(fin, fout), scale: 1 };
      case "fadein": return { opacity: fin, scale: 1 };
      case "fadeout": return { opacity: fout, scale: 1 };
      case "pop": return { opacity: Math.min(fin, fout), scale: 0.5 + 0.5 * back };
      case "zoom": return { opacity: Math.min(fin, fout), scale: 1.4 - 0.4 * ease };
      case "blink": return { opacity: (Math.sin(tp * Math.PI * 14) > -0.2 ? 1 : 0.2) * fout, scale: 1 };
      default: return { opacity: 1, scale: 1 };
    }
  }
  async function setLogoImage(file) {
    if (!E.using || !file || !/^image\//.test(file.type)) { alert("이미지(PNG) 파일을 선택하세요."); return; }
    if (E.using.logoUrl) { try { URL.revokeObjectURL(E.using.logoUrl); } catch (_) {} }
    E.using.logoUrl = URL.createObjectURL(file); E.using._logoFile = file;
    if (!E.using.logo) E.using.logo = { xPct: 80, yPct: 14, scale: 1.6, opacity: 1, fx: "fade", start: 0, dur: +(totalDur() || 5).toFixed(2) };
    try { await idbSet("sessLogo", file); } catch (_) {}
    renderLogo(); renderLogoCtl(); renderLogoLane(); scheduleSaveMeta();
  }
  function removeLogo() {
    if (!E.using) return;
    if (E.using.logoUrl) { try { URL.revokeObjectURL(E.using.logoUrl); } catch (_) {} }
    E.using.logoUrl = null; E.using._logoFile = null; E.using.logo = null; E.using._isTitle = false;
    idbDel("sessLogo").catch(() => {});
    renderLogo(); renderLogoCtl(); renderLogoLane(); scheduleSaveMeta();
  }

  // ════════════════════════════════════════════════════════════════
  // 🎬 타이틀 생성기 (참조사진 스타일 → Gemini → 투명화 → 타임라인 오버레이)
  // ════════════════════════════════════════════════════════════════
  function titleEndpoint() { if (/^(localhost|127\.0\.0\.1)$/.test(location.hostname)) return "http://127.0.0.1:8787/api/easy-title"; return "https://sc-pink.vercel.app/api/easy-title"; }
  function tmBlobToDataUri(blob) { return new Promise((res, rej) => { const fr = new FileReader(); fr.onload = () => res(fr.result); fr.onerror = () => rej(fr.error); fr.readAsDataURL(blob); }); }
  // ── 🎤 목소리 → 자막 (STT) — 자율컷 영상 음성 인식 → 15글자 이내 씽크 자막, 관리자 스타일 적용 ──
  function sttEndpoint() { if (/^(localhost|127\.0\.0\.1)$/.test(location.hostname)) return "http://127.0.0.1:8787/api/stt"; return "https://sc-pink.vercel.app/api/stt"; }
  // 🎚 영상/오디오에서 '음성만' 뽑아 16kHz 모노 WAV 로 압축 — Vercel 서버리스 본문 한도(약 4.5MB) 안에 들어가게 + Whisper 최적 포맷
  //   (영상 파일 통째로 base64 전송하면 배포본에서 413/연결 실패 → '목소리를 자막으로'가 안 되던 원인)
  function _encodeWav16(samples, sampleRate) {
    const n = samples.length, buf = new ArrayBuffer(44 + n * 2), view = new DataView(buf);
    const wr = (off, s) => { for (let i = 0; i < s.length; i++) view.setUint8(off + i, s.charCodeAt(i)); };
    wr(0, "RIFF"); view.setUint32(4, 36 + n * 2, true); wr(8, "WAVE"); wr(12, "fmt ");
    view.setUint32(16, 16, true); view.setUint16(20, 1, true); view.setUint16(22, 1, true);
    view.setUint32(24, sampleRate, true); view.setUint32(28, sampleRate * 2, true);
    view.setUint16(32, 2, true); view.setUint16(34, 16, true); wr(36, "data"); view.setUint32(40, n * 2, true);
    let off = 44; for (let i = 0; i < n; i++) { let s = Math.max(-1, Math.min(1, samples[i])); view.setInt16(off, s < 0 ? s * 0x8000 : s * 0x7fff, true); off += 2; }
    return buf;
  }
  async function _extractAudio16kWavUri(file) {
    const arr = await file.arrayBuffer();
    const AC = window.AudioContext || window.webkitAudioContext;
    if (!AC || typeof OfflineAudioContext === "undefined") throw new Error("no-audio-ctx");
    const tmp = new AC(); let decoded;
    try { decoded = await tmp.decodeAudioData(arr.slice(0)); } finally { try { tmp.close(); } catch (_) {} }
    const SR = 16000, dur = Math.max(0.05, decoded.duration || 0), frames = Math.max(1, Math.ceil(dur * SR));
    const off = new OfflineAudioContext(1, frames, SR);
    const src = off.createBufferSource(); src.buffer = decoded; src.connect(off.destination); src.start(0);
    const rendered = await off.startRendering();
    const blob = new Blob([_encodeWav16(rendered.getChannelData(0), SR)], { type: "audio/wav" });
    return await tmBlobToDataUri(blob);
  }
  // STT 로 보낼 {uri, mime} — 가능하면 음성만 압축, 실패하면(코덱 등) 원본으로 폴백
  async function sttAudioUri(file) {
    try { return { uri: await _extractAudio16kWavUri(file), mime: "audio/wav" }; }
    catch (_) { return { uri: await tmBlobToDataUri(file), mime: (file && file.type) || "video/mp4" }; }
  }
