    const MAX = 10;   // 한 자막(=한 줄) 최대 글자 — 사장님 요청: 10자에서 끊기(STT 청크·폴백·강제분할 모두 이 값 사용)
    // 🎤 1순위: STT 단어 타임스탬프로 '말하는 타이밍'에 정확히 싱크 (원래 잘 되던 방식). 실패 시 음성 길이에 균등 분배 폴백.
