    if (!chunks.length) { if (btn) { btn.disabled = false; btn.textContent = old; } return; }
    const base = caps[0] ? Object.assign({}, caps[0]) : null;   // 첫 칸 스타일 복사용(글씨 크기·위치 그대로 유지)
