        if (st) st.textContent = serverDown ? "😢 지금 자막 변환 서버에 연결이 안 돼요. 잠시 후 다시 시도해 주세요." : "😢 목소리를 못 알아들었어요 (영상에 말소리가 있는지·너무 작지 않은지 확인해 주세요).";
        if (btn) { btn.disabled = false; btn.textContent = old || "🎤 내 목소리로 자막 만들기"; }
