          let acc = 0;
          caps.forEach((c) => { const ch = (c.text || "").replace(/\s/g, "").length || 1; const d = span * ch / totalChars; c.start = +acc.toFixed(2); c.dur = +Math.max(0.4, d).toFixed(2); acc += d; });
          try { toast("🔄 자막 씽크를 다시 맞췄어요 (음성 길이 기준)"); } catch (_) {}
