        // 나레이션 음성이 없으면(내 목소리/자동자막) → 기존 자막 비우고 영상 목소리를 다시 듣고 '날것 그대로' 재추출
        const prevTexts = (E.using.texts || []).slice();   // 실패 시 복원용
        E.using.texts = (E.using.texts || []).filter((t) => t.locked);   // 중복 방지
