    if (E.using.voiceUrl) { try { URL.revokeObjectURL(E.using.voiceUrl); } catch (_) {} }
    E.using.voiceUrl = null; E.using.voiceBlob = null; E.using.voiceDur = 0; E.using._voiceChanged = true;
