      const ext = outType.indexOf("mp4") >= 0 ? "mp4" : "webm";
      const base = String(file.name || "video").replace(/\.[^.]+$/, "") || "video";
      return new File([blob], base + "." + ext, { type: outType });       // File 로 감싸 이름/확장자 부여
